  ],
  "field_notes": {
    "company": "Predicted 'Primo Family Restaurant'; gold is 'Family Restaurant'. The image shows 'Primo' in large text above 'Family Restaurant'.",
    "date": "Format mismatch: '5/3/19' vs '2019-03-05'.",
    "subtotal": "Correct.",
    "tax": "Correct.",
    "total": "Correct.",
    "line_items": "Failed on line_total. For the first item, predicted '7.5' (unit price) instead of '22.50' (line total). For the second item, predicted '27.0' instead of '27.00' (though value is mathematically same, the first error causes reconciliation failure)."
  }
